      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  var l = (f.getItemValue('nam') == 0);
  if (l) {
    f.getItem('tu_ky').value = f.getItem('den_ky').value = (new Date()).getMonth() + 1;
    f.getItem('nam').value = f.getItem('nam2').value = (new Date()).getFullYear();
  }
  f.live(f.getItem('tu_ky'));
  changeLookupReadonly(f, 'ma_ytcp', true);
  if (f._costUnit == 1 || !l) f.setReferenceKeyFilter('ma_ytcp');
  if (!l) onChange$Report$CostUnit(f.getItem('ma_dvcs'), true);
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
   var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('mau_bc');
      g._hiddenFields = [
       {Fields: 'dd_dk, ps_tk, tong_gt, dd_ck, gia', Value: (x == '10' ||  x == '30')},
       {Fields: 'dd_dk_nt, ps_tk_nt, tong_gt_nt, dd_ck_nt, gia_nt', Value: (x == '10' || x == '20')}
      ];
      var d1 = f.getItem('tu_ky').value, d2 = f.getItem('den_ky').value, n1 = f.getItem('nam').value, n2 = f.getItem('nam2').value;
      g._alterTitle = [null, [['%d1', d1, true], ['%n1', n1, true],['%d2', d2, true], ['%n2', n2, true]]];
      remove$GridReport$Filter(g);
      break;
    case 'SetReadOnlyField':
      setItemReadOnly(f, 'ma_bp', result[0].Value, false);
      setItemReadOnly(f, 'so_lsx', result[1].Value, false);
      break;
    default:
      break;
  }
}
function onChange$Report$CostUnit(o, force) {
  var f = o.parentForm;
  if (f._costUnit == 1 && !force) f.setItemValue('ma_ytcp', '');
  f.setReferenceKeyFilter('ma_ytcp');
  if (f._objectUnit == '1') f.request('GetResponse', 'SetReadOnlyField', ['ma_dvcs']);
}/* </flatten> */

